// En n8n el body del webhook llega bajo .body
const raw  = $input.first().json;
const body = raw.body || raw;

const data = body.data    || {};
const key  = data.key     || {};
const msg  = data.message || {};

if (key.fromMe === true) return [];

const remoteJid = key.remoteJid || body.sender || '';
if (!remoteJid || remoteJid.includes('@g.us')) return [];

const tipo = data.messageType || '';
if (!['conversation', 'extendedTextMessage'].includes(tipo)) return [];

const texto = msg.conversation || msg.extendedTextMessage?.text || '';
if (!texto.trim()) return [];

const numero = remoteJid.replace('@s.whatsapp.net', '').replace('@c.us', '');

// Calcular fecha y hora actual en zona horaria de Bogota
const tz = 'America/Bogota';
const ahora = new Date();
const partes = ahora.toLocaleString('en-CA', { timeZone: tz, year: 'numeric', month: '2-digit', day: '2-digit', hour: '2-digit', minute: '2-digit', hour12: false });
const [fechaActual, horaActual] = partes.split(', ');
const diasSemana = ['domingo','lunes','martes','miercoles','jueves','viernes','sabado'];
const dow = new Date(fechaActual + 'T12:00:00').getDay();
const diaSemana = diasSemana[dow];

// Calcular fecha maxima permitida (hoy + 5 dias)
const limite = new Date(fechaActual + 'T12:00:00');
limite.setDate(limite.getDate() + 5);
const fechaLimite = limite.toISOString().split('T')[0];

return [{
  json: {
    numero,
    texto: texto.trim(),
    nombre: data.pushName || 'Cliente',
    sessionId: `barberia_${numero}`,
    fechaActual,
    horaActual,
    diaSemana,
    fechaLimite
  }
}];

const texto = $('Extraer Mensaje').item.json.texto.toLowerCase()
  .normalize('NFD').replace(/[\u0300-\u036f]/g, '');
const nombre = $('Registrar Cliente').item.json.nombre;
const registrado = nombre && nombre.toLowerCase() !== 'no registrado' && nombre.toLowerCase() !== 'cliente';

const kwSimple = $('Intension').first().json.intencion
const esInfo = kwSimple.some(kw => texto.includes(kw));

const kwTool = $('herramienta').first().json.herramienta
const necesitaTool = kwTool.some(kw => texto.includes(kw));

const esSimple = registrado && esInfo && !necesitaTool;

return [{ json: { ...$input.first().json, esSimple } }];

const historial = $('Leer Historial').all();
const extraer = $('Extraer Mensaje').item.json;
const registrar = $('Registrar Cliente').item.json;
const fechaHora = $('Fecha y Hora Actual').item.json;

const systemMsg = $('Prompt del sistema').first().json.systemPrompt

// Construir mensajes desde historial (viene DESC, invertir)
const messages = [];
const filas = historial.filter(r => r.json && r.json.message).reverse();
for (const row of filas) {
  const msg = typeof row.json.message === 'string' ? JSON.parse(row.json.message) : row.json.message;
  const texto = msg.content || msg.data?.content || '';
  if (!texto || !texto.trim()) continue;
  const role = msg.type === 'human' ? 'user' : 'assistant';
  // Evitar mensajes consecutivos del mismo rol
  if (messages.length > 0 && messages[messages.length - 1].role === role) {
    messages[messages.length - 1].content += '\n' + texto;
  } else {
    messages.push({ role, content: texto });
  }
}

// Asegurar que el primer mensaje sea de usuario
while (messages.length > 0 && messages[0].role !== 'user') {
  messages.shift();
}

// Mensaje actual del usuario
const nombre = registrar.nombre || 'NO REGISTRADO';
const userText = `[Cliente: ${nombre} | Numero: ${extraer.numero}]\n[Hoy: ${fechaHora.fechaLegible} a las ${fechaHora.horaActual}]\n\nMensaje: ${extraer.texto}`;
messages.push({ role: 'user', content: userText });

const body = {
  model: 'claude-haiku-4-5-20251001',
  max_tokens: 500,
  cache_control: { "type": "ephemeral" },
  system: [
    {
      type: 'text',
      text: systemMsg,
      cache_control: { type: 'ephemeral' }
    }
  ],
  messages
};

return [{ json: { requestBody: body, sessionId: extraer.sessionId, userText: extraer.texto } }];

const response = $input.first().json;
const content = response.content || [];
const text = content.map(c => c.text || '').join('');
const sessionId = $('Construir Request Cached').item.json.sessionId;
const userText = $('Construir Request Cached').item.json.userText;

const humanMsg = JSON.stringify({type:'human',content:userText,additional_kwargs:{},response_metadata:{}});
const aiMsg = JSON.stringify({type:'ai',content:text,additional_kwargs:{},response_metadata:{}});

return [{
  json: {
    output: text || 'Lo siento, no pude procesar tu consulta.',
    sessionId,
    userText,
    aiText: text,
    humanMsg,
    aiMsg
  }
}];
